// n8n Function node
// Devuelve 1 item con { conversation_text, total_messages, session_id }

function getArrayFromAny(items) {
  // Caso: un solo item con el array en root o en alguna clave
  const first = items[0]?.json;

  const isArr = (v) => Array.isArray(v);
  const tryParse = (s) => { try { return JSON.parse(s); } catch { return null; } };

  // 1) Array directo en el root del json
  if (isArr(first)) return first;

  // 2) Array en claves comunes
  const candidatesObj = [first?.messages, first?.conversation, first?.data];
  for (const c of candidatesObj) if (isArr(c)) return c;

  // 3) Array como string JSON en claves comunes
  const candidatesStr = [first?.raw, first?.raw_json, first?.input, first?.payload, first?.body];
  for (const c of candidatesStr) {
    if (typeof c === 'string') {
      const parsed = tryParse(c);
      if (isArr(parsed)) return parsed;
    }
  }

  // 4) Si nada de lo anterior: asume que cada item ES un registro de mensaje
  const asItems = items.map(it => it.json).filter(x => x && x.message);
  if (asItems.length) return asItems;

  // 5) fallback vacío
  return [];
}

// ---------- CONFIG OPCIONAL ----------
const TARGET_SESSION_ID = null; // e.g., "7764470220" para filtrar; déjalo en null para no filtrar
const PREFIX_USUARIO = 'Usuario';
const PREFIX_BOT = 'Bot';
// -------------------------------------

const items = $input.all();
let records = getArrayFromAny(items);

// Filtra y ordena
records = records
  .filter(r => r?.message?.type && r?.message?.content != null)
  .filter(r => !TARGET_SESSION_ID || r.session_id === TARGET_SESSION_ID)
  .sort((a, b) => (Number(a.id) || 0) - (Number(b.id) || 0));

// Limpieza de contenido
const strip = (txt) => {
  if (typeof txt !== 'string') return '';
  return txt
    .replace(/^\s*(Mensasje|Mensaje)\s*:\s*/i, '')
    .replace(/  \n/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    .trim();
};

const role = (type) => (type === 'human' ? PREFIX_USUARIO : (type === 'ai' ? PREFIX_BOT : String(type)));

const lines = [];
for (const r of records) {
  const content = strip(r.message.content);
  if (!content) continue;
  lines.push(`${role(r.message.type)}: ${content}`);
}

return [{
  json: {
    conversation_text: lines.join('\n'),
    total_messages: lines.length,
    session_id: TARGET_SESSION_ID || (records[0]?.session_id ?? null),
  }
}];

